mapper.select:


    AND c.CONTRACT_YEAR = #{contractYear}


    AND cust.COMPANY_CD = #{customerCode}


    AND cust.MANAGE_CD = #{manageDeptCode}


    AND part.COMPANY_CD = #{partnerCode}


    AND s.SW_NM LIKE CONCAT('%', #{swNm}, '%')


    AND c.SUB_CD LIKE CONCAT('%', #{subCode}, '%')


    AND p.PARTNER_CONTRACT_CD = #{partnerContractCd}



        ORDER BY ${sortBy}


        ORDER BY c.REG_DT DESC


LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*)
FROM TS_WORK_SW_CONTRACT c
LEFT JOIN TS_WORK_SW_PARTNER p ON c.SUB_CD = p.SUB_CD
LEFT JOIN TS_WORK_SW s ON p.SW_CD = s.SW_CD
LEFT JOIN V_ORGANIZATION_STRUCTURE cust ON c.DEPT_CD = cust.ORIGIN_CD
LEFT JOIN V_ORGANIZATION_STRUCTURE part ON p.COMP_CD = part.ORIGIN_CD
WHERE c.DELETE_YN != 'Y'

    AND c.CONTRACT_YEAR = #{contractYear}


    AND cust.COMPANY_CD = #{customerCode}


    AND cust.MANAGE_CD = #{manageDeptCode}


    AND part.COMPANY_CD = #{partnerCode}


    AND s.SW_NM LIKE CONCAT('%', #{swNm}, '%')
